class Solution:
    def valueAfterKSeconds(self, n: int, k: int) -> int:
        MOD = 10**9 + 7
        dp = [[1] * (n) for _ in range(k + 1)]

        for t in range(1, k + 1):
            for i in range(1, n):
                dp[t][i] = (dp[t][i - 1] + dp[t - 1][i]) % MOD

        return dp[k][n - 1]
